export type Genre =
  | 'AMBIENT + CHILL'
  | 'CLASSICAL'
  | 'DNB + RAVE'
  | 'DRAMA + TALK'
  | 'DUB + REGGAE'
  | 'ECLECTIC'
  | 'HIP HOP + RNB'
  | 'HOUSE + UKG'
  | 'JAZZ + EXOTICA'
  | 'LEGENDS + ERAS'
  | 'ROCK + INDIE'
  | 'SOUL + FUNK';

export interface Station {
  id: string;
  name: string;
  description: string;
  streamUrl: string;
  websiteUrl: string;
  genre: Genre | Genre[];
}

export function stationInGenre(station: Station, genre: Genre): boolean {
  return Array.isArray(station.genre)
    ? station.genre.includes(genre)
    : station.genre === genre;
}

